import React, { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import { Box, Card, CardContent, Typography, CircularProgress, TextField, Button } from "@mui/material";
import { format, parseISO, isSameDay, isThisMonth, isThisYear } from "date-fns"; // Importing date-fns functions

function EmpDetails() {
  const { user_id } = useParams();
  const [workReports, setWorkReports] = useState([]);
  const [filteredReports, setFilteredReports] = useState([]);
  const [employeeName, setEmployeeName] = useState("");
  const [companies, setCompanies] = useState({});
  const [loading, setLoading] = useState(true);
  const [searchDate, setSearchDate] = useState("");
  const [searchCompany, setSearchCompany] = useState("");
  const [filterType, setFilterType] = useState(""); // For Today/This Month/This Year filter

  useEffect(() => {
    const fetchData = async () => {
      try {
        // Fetch Work Reports
        const workResponse = await fetch(`http://localhost:5000/auth/${user_id}/work-reports`);
        const workData = await workResponse.json();

        // Sort reports by last modified (latest first)
        workData.sort((a, b) => new Date(b.date) - new Date(a.date));
        setWorkReports(workData);
        setFilteredReports(workData);

        // Fetch Employee Details
        const employeeResponse = await fetch("http://localhost:5000/auth");
        const employeeData = await employeeResponse.json();
        const employee = employeeData.find(emp => emp.id === parseInt(user_id));
        setEmployeeName(employee ? employee.name : "Unknown");

        // Fetch Company Details
        const companyResponse = await fetch("http://localhost:5000/companies");
        const companyData = await companyResponse.json();
        const companyMap = {};
        companyData.forEach(company => {
          companyMap[company.id] = company.company_name;
        });
        setCompanies(companyMap);

        setLoading(false);
      } catch (error) {
        console.error("Error fetching data:", error);
        setLoading(false);
      }
    };

    fetchData();
  }, [user_id]);

  // Filter Reports by Date and Company Name
  useEffect(() => {
    let filtered = workReports;

    // Apply filter based on filterType (Today, This Month, This Year)
    if (filterType === "today") {
      const today = new Date();
      filtered = filtered.filter(report => isSameDay(parseISO(report.date), today));
    } else if (filterType === "thisMonth") {
      filtered = filtered.filter(report => isThisMonth(parseISO(report.date)));
    } else if (filterType === "thisYear") {
      filtered = filtered.filter(report => isThisYear(parseISO(report.date)));
    } else if (searchDate) {
      const parsedSearchDate = parseISO(searchDate); // Parse the search date
      filtered = filtered.filter(report => isSameDay(parseISO(report.date), parsedSearchDate));
    }

    if (searchCompany) {
      filtered = filtered.filter(report =>
        companies[report.company_id]?.toLowerCase().includes(searchCompany.toLowerCase())
      );
    }

    setFilteredReports(filtered);
  }, [searchDate, searchCompany, workReports, companies, filterType]);

  return (
    <Box sx={{ padding: 3, maxWidth: 800, margin: "auto" }}>
      <Typography variant="h4" sx={{ textAlign: "center", marginBottom: 2 }}>
        Work Reports - {employeeName}
      </Typography>

      {/* Search and Filter Inputs */}
      <Box sx={{ display: "flex", gap: 2, marginBottom: 2 }}>
        <TextField
          label="Search by Date"
          type="date"
          InputLabelProps={{ shrink: true }}
          value={searchDate}
          onChange={(e) => setSearchDate(e.target.value)}
          fullWidth
        />
        <TextField
          label="Search by Company Name"
          value={searchCompany}
          onChange={(e) => setSearchCompany(e.target.value)}
          fullWidth
        />
      </Box>

      {/* Filter Buttons */}
      <Box sx={{ display: "flex", gap: 2, marginBottom: 2 }}>
        <Button variant="contained" onClick={() => setFilterType("today")}>
          Today
        </Button>
        <Button variant="contained" onClick={() => setFilterType("thisMonth")}>
          This Month
        </Button>
        <Button variant="contained" onClick={() => setFilterType("thisYear")}>
          This Year
        </Button>
      </Box>

      {/* Loading Spinner */}
      {loading ? (
        <Box sx={{ textAlign: "center", marginTop: 4 }}>
          <CircularProgress />
        </Box>
      ) : filteredReports.length > 0 ? (
        filteredReports.map((report) => (
          <Card key={report.id} sx={{ marginBottom: 2, padding: 2, boxShadow: 3 }}>
            <CardContent>
              <Typography variant="h6" sx={{ fontWeight: "bold" }}>
                {report.machine_name}
              </Typography>
              <Typography variant="body2" color="text.secondary">
                Date: {format(parseISO(report.date), "dd/MM/yyyy")}
              </Typography>
              <Typography variant="body2">
                <strong>Nature of Complaint:</strong> {report.nature_of_complaint}
              </Typography>
              <Typography variant="body2">
                <strong>Solution:</strong> {report.solution}
              </Typography>
              <Typography variant="body2">
                <strong>Time:</strong> {new Date(report.in_time).toLocaleTimeString()} - {new Date(report.out_time).toLocaleTimeString()}
              </Typography>
              <Typography variant="body2">
                <strong>Status:</strong> {report.status}
              </Typography>
              <Typography variant="body2">
                <strong>Assistant:</strong> {report.assistant_name}
              </Typography>
              <Typography variant="body2">
                <strong>Company:</strong> {companies[report.company_id] || "Unknown"}
              </Typography>
            </CardContent>
          </Card>
        ))
      ) : (
        <Typography sx={{ textAlign: "center", marginTop: 4 }}>No work reports found.</Typography>
      )}
    </Box>
  );
}

export default EmpDetails;
